package main

import (
	"context"
	"fmt"
	"sync"
	"time"
)

// Simplified reproduction of k8s scheduler shutdown deadlock.
// The bug: ScheduleOne blocks on queue.Pop(), shutdown calls queue.Close(),
// but Close() needs the lock that Pop() holds.

type SchedulingQueue struct {
	mu     sync.Mutex
	cond   *sync.Cond
	items  []string
	closed bool
}
